(function(){const STORAGE_KEY='kl-force-dark-theme';const THEME_ATTR='data-force-dark-theme';const THEME_MODE_ATTR='data-force-dark-mode';const TRANSITION_LOCK_ATTR='data-force-dark-transition-lock';const THEME_MODES=['system','dark','light'];const systemDarkQuery=window.matchMedia?window.matchMedia('(prefers-color-scheme: dark)'):null;let themeMode=readStoredMode();let runtimePromise=null;let themeRuntimeInitialized=false;function normalizeMode(mode){return THEME_MODES.includes(mode)?mode:'system';}
function readStoredMode(){try{return normalizeMode(localStorage.getItem(STORAGE_KEY)||'system');}catch(error){return'system';}}
function writeStoredMode(mode){try{localStorage.setItem(STORAGE_KEY,normalizeMode(mode));}catch(error){console.warn('[theme-force-dark] 无法写入本地主题状态',error);}}
function setThemeState(state){document.documentElement.setAttribute(THEME_ATTR,state);}
function setThemeMode(mode){document.documentElement.setAttribute(THEME_MODE_ATTR,normalizeMode(mode));}
function setTransitionLock(locked){document.documentElement.setAttribute(TRANSITION_LOCK_ATTR,locked?'on':'off');}
function waitForNextPaint(){return new Promise((resolve)=>{requestAnimationFrame(()=>{requestAnimationFrame(resolve);});});}
function getToggleButtons(){return Array.from(document.querySelectorAll('[data-theme-force-toggle]'));}
function isDarkByMode(mode){return mode==='dark'||(mode==='system'&&!!(systemDarkQuery&&systemDarkQuery.matches));}
function getNextMode(mode){const currentIndex=THEME_MODES.indexOf(normalizeMode(mode));return THEME_MODES[(currentIndex+1)%THEME_MODES.length];}
function getModeLabel(mode){switch(mode){case'dark':return'深色';case'light':return'浅色';default:return'跟随系统';}}
function getModeDescription(mode){if(mode!=='system'){return getModeLabel(mode);}
return isDarkByMode('system')?'跟随系统（当前系统为深色）':'跟随系统（当前系统为浅色）';}
function getToggleText(mode,busy){if(busy){return'正在切换主题';}
const currentMode=normalizeMode(mode);const nextMode=getNextMode(currentMode);return'当前为'+getModeDescription(currentMode)+'，点击切换为'+getModeLabel(nextMode);}
function syncToggleButtons(mode,busy,forcedState){const currentMode=normalizeMode(mode);const enabled=isDarkByMode(currentMode);const state=forcedState||(busy?'loading':(enabled?'on':'off'));setThemeMode(currentMode);setThemeState(state);getToggleButtons().forEach((button)=>{button.dataset.forceDarkState=state;button.dataset.forceDarkMode=currentMode;button.setAttribute('aria-pressed',enabled?'true':'false');const label=getToggleText(currentMode,busy||state==='pending'||state==='loading');button.setAttribute('aria-label',label);button.setAttribute('title',label);});}
function loadDarkReaderRuntime(){if(window.DarkReader){return Promise.resolve(window.DarkReader);}
if(runtimePromise){return runtimePromise;}
runtimePromise=new Promise((resolve,reject)=>{const existingScript=document.querySelector('script[data-darkreader-runtime="true"]');if(existingScript){if(window.DarkReader){resolve(window.DarkReader);return;}
existingScript.addEventListener('load',function(){resolve(window.DarkReader);},{once:true});existingScript.addEventListener('error',reject,{once:true});return;}
reject(new Error('Dark Reader 模板脚本不存在'));});return runtimePromise;}
async function applyThemeMode(mode,options={}){const currentMode=normalizeMode(mode);const enabled=isDarkByMode(currentMode);const shouldPersist=options.persist!==false;setTransitionLock(true);syncToggleButtons(currentMode,true);try{if(enabled){const DarkReader=await loadDarkReaderRuntime();if(typeof DarkReader.setFetchMethod==='function'){DarkReader.setFetchMethod(window.fetch);}
DarkReader.enable({brightness:100,contrast:90,sepia:0});}else if(window.DarkReader&&typeof window.DarkReader.disable==='function'){window.DarkReader.disable();}
themeMode=currentMode;if(shouldPersist){writeStoredMode(currentMode);}
syncToggleButtons(currentMode,false);await waitForNextPaint();setTransitionLock(false);}catch(error){console.error('[theme-force-dark] 主题切换失败',error);syncToggleButtons(themeMode,false);await waitForNextPaint();setTransitionLock(false);}}
function bindToggleButtons(){getToggleButtons().forEach((button)=>{if(button.dataset.forceDarkBound==='true'){return;}
button.dataset.forceDarkBound='true';button.addEventListener('click',function(){applyThemeMode(getNextMode(themeMode));});});}
function initializeForceDarkTheme(){bindToggleButtons();const currentState=document.documentElement.getAttribute(THEME_ATTR);syncToggleButtons(themeMode,false,isDarkByMode(themeMode)&&currentState==='pending'?'pending':undefined);if(systemDarkQuery){const handleSystemThemeChange=function(){if(themeMode==='system'){applyThemeMode('system',{persist:false});}};if(!systemDarkQuery.__forceDarkBound){if(typeof systemDarkQuery.addEventListener==='function'){systemDarkQuery.addEventListener('change',handleSystemThemeChange);}else if(typeof systemDarkQuery.addListener==='function'){systemDarkQuery.addListener(handleSystemThemeChange);}
systemDarkQuery.__forceDarkBound=true;}}}
function startForceDarkTheme(){initializeForceDarkTheme();if(!themeRuntimeInitialized&&(themeMode==='dark'||(themeMode==='system'&&isDarkByMode('system')))){applyThemeMode(themeMode,{persist:false});}
themeRuntimeInitialized=true;}
function subscribeToPageChanges(callback){if(typeof document$!=='undefined'&&typeof document$.subscribe==='function'){document$.subscribe(()=>{window.requestAnimationFrame(()=>{callback();});});return;}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',callback,{once:true});return;}
callback();}
subscribeToPageChanges(startForceDarkTheme);})();